import time
from functools import wraps

class TokenBucket:
    def __init__(self, rate: float, capacity: int):
        self.rate = rate  # tokens per second
        self.capacity = capacity
        self.tokens = capacity
        self.last_update = time.time()

    def consume(self, tokens=1) -> bool:
        now = time.time()
        elapsed = now - self.last_update
        self.tokens = min(self.capacity, self.tokens + elapsed * self.rate)
        self.last_update = now
        if self.tokens >= tokens:
            self.tokens -= tokens
            return True
        return False

buckets = {}  # {user_id: TokenBucket}

def rate_limit(requests_per_minute: int):
    rate = requests_per_minute / 60.0
    def decorator(fn):
        @wraps(fn)
        async def wrapper(user=Depends(get_current_user), *args, **kwargs):
            uid = user['id']
            if uid not in buckets:
                buckets[uid] = TokenBucket(rate, requests_per_minute)
            if not buckets[uid].consume():
                raise HTTPException(429, 'Rate limit exceeded')
            return await fn(*args, **kwargs)
        return wrapper
    return decorator

