import time, functools
from enum import Enum

class CircuitState(Enum):
    CLOSED = 'closed'   # Normal
    OPEN = 'open'       # Failing, reject immediately
    HALF_OPEN = 'half_open'  # Testing recovery

class CircuitBreaker:
    def __init__(self, failure_threshold=5, timeout=60):
        self.failure_threshold = failure_threshold
        self.timeout = timeout
        self.failures = 0
        self.last_failure_time = None
        self.state = CircuitState.CLOSED

    def call(self, fn, *args, **kwargs):
        if self.state == CircuitState.OPEN:
            if time.time() - self.last_failure_time > self.timeout:
                self.state = CircuitState.HALF_OPEN
            else:
                raise Exception('Circuit OPEN — request rejected')

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as e:
            self._on_failure()
            raise e

    def _on_success(self):
        self.failures = 0
        self.state = CircuitState.CLOSED

    def _on_failure(self):
        self.failures += 1
        self.last_failure_time = time.time()
        if self.failures >= self.failure_threshold:
            self.state = CircuitState.OPEN

import time, random

def retry(max_attempts=3, base_delay=1.0, max_delay=30.0, jitter=True):
    def decorator(fn):
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except RetryableError as e:
                    if attempt == max_attempts - 1:
                        raise
                    delay = min(base_delay * (2 ** attempt), max_delay)
                    if jitter:
                        delay += random.uniform(0, delay * 0.1)
                    print(f'Retry {attempt+1}/{max_attempts} after {delay:.1f}s: {e}')
                    time.sleep(delay)
        return wrapper
    return decorator

class RetryableError(Exception): pass

@retry(max_attempts=3, base_delay=2.0)
def call_api(endpoint):
    resp = requests.get(endpoint)
    if resp.status_code == 429:
        raise RetryableError('Rate limited')
    if resp.status_code >= 500:
        raise RetryableError('Server error')
    return resp.json()

import logging, json, sys
from datetime import datetime

class JSONFormatter(logging.Formatter):
    def format(self, record):
        log_data = {
            'timestamp': datetime.utcnow().isoformat() + 'Z',
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'module': record.module,
            'function': record.funcName,
            'line': record.lineno,
        }
        if record.exc_info:
            log_data['exception'] = self.formatException(record.exc_info)
        if hasattr(record, 'user_id'):
            log_data['user_id'] = record.user_id
        if hasattr(record, 'request_id'):
            log_data['request_id'] = record.request_id
        return json.dumps(log_data)

handler = logging.StreamHandler(sys.stdout)
handler.setFormatter(JSONFormatter())
logger = logging.getLogger('api')
logger.addHandler(handler)
logger.setLevel(logging.INFO)

